using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load CSV as raw data (Churned is a string: "Yes"/"No")
var rawData = mlContext.Data.LoadFromTextFile<ChurnRawData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" to a boolean Label column
var rawItems = mlContext.Data.CreateEnumerable<ChurnRawData>(rawData, reuseRowObject: false);
var labeledItems = rawItems.Select(r => new ChurnLabeledData
{
    Age = r.Age,
    Income = r.Income,
    Region = r.Region,
    PurchaseHistory = r.PurchaseHistory,
    Label = string.Equals(r.Churned, "Yes", StringComparison.OrdinalIgnoreCase)
});
var data = mlContext.Data.LoadFromEnumerable(labeledItems);

var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(ChurnLabeledData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnLabeledData.Age),
        nameof(ChurnLabeledData.Income),
        "RegionEncoded",
        nameof(ChurnLabeledData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on held-out test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
Console.WriteLine($"AUC:      {metrics.AreaUnderRocCurve:F4}");
